code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 100vh;
  background: #e9e1c5;
  overflow: hidden;
}

.nav-container {
  width: 100%;
  position: relative;
}

.nav {
  width: 95%;
  margin: 0 auto;
  padding: 2em 0;
  display: flex;
  border-bottom: 1px solid #000;
}

.nav-item {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
}

.nav-item:nth-child(2) {
  flex: 4;
}

.nav-item:first-child {
  margin-right: auto;
  text-align: left;
}

.nav-item:last-child {
  margin-left: auto;
}

.nav-item a {
  text-decoration: none;
  color: #000;
  font-family: "Neue Montreal";
}

.nav-logo a {
  font-family: "Voyage";
  font-size: 20px;
  font-weight: 600;
}

.nav-cta a {
  text-transform: uppercase;
  font-size: 14px;
}

.nav-links a {
  padding: 0 2em;
  font-size: 14px;
}

@media (max-width: 900px) {
  .nav {
    width: 100%;
  }

  .nav-links,
  .nav-cta {
    display: none;
  }
}

.hero-container {
  position: relative;
  z-index: 10000;
  width: 100%;
}

.hero > * {
  position: relative;
}

.hero {
  width: 30%;
  margin: 0 auto;
  text-align: center;
  padding: 4em 0;
}

h1 {
  font-family: "Voyage";
  font-weight: 500;
  font-size: 5vw;
}

.cta button {
  background: #000;
  color: #fff;
  border: none;
  outline: none;
  margin: 4em 0 0 0;
  padding: 1.6em 3.2em;
  text-transform: uppercase;
  font-size: 12px;
}

p {
  margin: 4em 0 0 0;
  font-family: "Neue Montreal";
  font-size: 14px;
}

.bg-gradient {
  position: absolute;
  top: 40%;
  left: 50%;
  transform: translate(-50%, -50%);
  z-index: 0;
}

.blob {
  display: flex;
  justify-content: center;
  align-items: center;
  animation: animate-blob 4s ease-in-out infinite;
}

@keyframes animate-blob {
  0% {
    border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%;
  }
  50% {
    border-radius: 30% 60% 70% 40% / 50% 60% 30% 60%;
  }
  100% {
    border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%;
  }
}

.blob-1 {
  position: absolute;
  top: 20%;
  left: 5%;
  width: 400px;
  height: 400px;
  background: url(./img-1.jpg) no-repeat 50% 50%;
  background-size: cover;
}

.blob-2 {
  position: absolute;
  top: 50%;
  right: 10%;
  width: 160px;
  height: 160px;
  background: url(./img-2.jpg) no-repeat 50% 50%;
  background-size: cover;
  animation-delay: 1s;
}

.blob-3 {
  position: absolute;
  top: 20%;
  right: 25%;
  width: 100px;
  height: 100px;
  border: 1px solid rgba(0, 0, 0, 1);
  animation-delay: 2s;
}
